create table dirkspzm32.mde_res_akt (
    sid            varchar2(2 char) not null enable,
    firma_nr       number(2, 0) not null enable,
    res_id         number(*, 0) not null enable,
    res_name       varchar2(20 char) not null enable,
    status         varchar2(2 char) not null enable,
    create_date    date not null enable,
    change_date    date,
    auftrag        varchar2(20 char),
    leitzahl       number(*, 5),
    fa_ag          number(*, 0),
    fa_upos        number(*, 0),
    mde_bstd_min   number(*, 12),
    lhm_id_akt     varchar2(20 char),
    lhm_id_next    varchar2(20 char),
    lhm_id_rw_akt  varchar2(20 char),
    lhm_id_rw_next varchar2(20 char),
    res_status     number(*, 0),
    mde_menge      number(*, 3),
    mde_menge_t    number(*, 3),
    mde_prod_min   number(*, 12),
    akt_aufgabe    varchar2(1 char)
);

alter table dirkspzm32.mde_res_akt
    add constraint ix_mde_res_akt
        unique ( res_name,
                 firma_nr,
                 sid )
            using index enable;

alter table dirkspzm32.mde_res_akt
    add constraint pk_mde_res_akt
        primary key ( res_id,
                      firma_nr,
                      sid )
            using index enable;


